import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';

const config = {
  clientId: 'mobile_app_client_123',
  clientSecret: 'secret_abc123xyz456',
  redirectUrl: 'com.mobileapp://oauth',
  scopes: ['openid', 'profile', 'email'],
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
    tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  },
};

const App = () => {
  const [authState, setAuthState] = useState(null);

  const handleLogin = async () => {
    try {
      const newAuthState = await authorize(config);
      setAuthState(newAuthState);
    } catch (error) {
      console.error('Failed to log in', error);
    }
  };

  const handleRefreshToken = async () => {
    try {
      const newAuthState = await refresh(config, {
        refreshToken: authState?.refreshToken,
      });
      setAuthState(newAuthState);
    } catch (error) {
      console.error('Failed to refresh token', error);
    }
  };

  useEffect(() => {
    // Auto-refresh token on mount if present
    if (authState?.refreshToken) {
      handleRefreshToken();
    }
  }, []);

  return (
    <View>
      <Text>{authState ? 'Logged in' : 'Logged out'}</Text>
      <Button title="Login" onPress={handleLogin} disabled={authState !== null} />
      <Button title="Refresh Token" onPress={handleRefreshToken} disabled={!authState?.refreshToken} />
    </View>
  );
};

export default App;